package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testWithEscapeChar() {
        CSVFormat format = CSVFormat.DEFAULT;
        char escapeChar = '\\';

        CSVFormat newFormat = format.withEscape(escapeChar);

        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertEquals(Character.valueOf(escapeChar), newFormat.getEscapeCharacter());
    }

    @Test
    void testWithEscapeCharacterObject() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        Character escapeChar = '\\';

        Method withEscapeCharMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
        withEscapeCharMethod.setAccessible(true);

        CSVFormat newFormat = (CSVFormat) withEscapeCharMethod.invoke(format, escapeChar);

        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertEquals(escapeChar, newFormat.getEscapeCharacter());
    }

    @Test
    void testWithEscapeNullCharacterObject() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        Method withEscapeCharMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
        withEscapeCharMethod.setAccessible(true);

        CSVFormat newFormat = (CSVFormat) withEscapeCharMethod.invoke(format, (Object) null);

        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertNull(newFormat.getEscapeCharacter());
    }
}
